// Transform all SerpAPI responses into ocupacao_horaria rows.
// Each input item = one beach's SerpAPI response; output = many rows total.
// Pairs each response back to its praia_id by index.

const responses = $input.all();
const praias = $('Buscar Praias').all();

// Sunday=0 … Saturday=6 — matches JavaScript's Date.getDay() used in the frontend.
const DIA = { Sunday: 0, Monday: 1, Tuesday: 2, Wednesday: 3, Thursday: 4, Friday: 5, Saturday: 6 };

const rows = [];
for (let i = 0; i < responses.length; i++) {
  const praia_id = praias[i].json.id;
  const rawPT = responses[i].json.popular_times;
  const popularTimes = Array.isArray(rawPT) ? rawPT : [];

  if (popularTimes.length === 0) {
    console.log(`No popular_times data for praia_id=${praia_id} — skipping`);
    continue;
  }

  let count = 0;
  for (const day of popularTimes) {
    const dia_semana = DIA[day.day];
    if (dia_semana == null) continue;

    for (const slot of (day.popular_times_by_day ?? [])) {
      if (slot.hour == null || slot.busyness_score == null) continue;
      rows.push({
        json: {
          praia_id,
          dia_semana,
          hora: slot.hour,
          nivel_ocupacao: slot.busyness_score,
        }
      });
      count++;
    }
  }
  console.log(`praia_id=${praia_id}: ${count} hour slots extracted`);
}

console.log(`Total rows: ${rows.length}`);
return rows;

// Build batched INSERT ... ON CONFLICT SQL statements (1000 rows per batch).
// Large datasets are split to avoid hitting SQL string size limits.

const rows = $input.all().map(i => i.json);
console.log(`Total occupation rows to upsert: ${rows.length}`);

if (rows.length === 0) return [];

const BATCH = 1000;
const sqls = [];

for (let i = 0; i < rows.length; i += BATCH) {
  const batch = rows.slice(i, i + BATCH);
  const values = batch
    .map(r => `(${r.praia_id}, ${r.dia_semana}, ${r.hora}, ${r.nivel_ocupacao}, 'serpapi_popular_times', NOW())`)
    .join(',\n');

  sqls.push(
    `INSERT INTO ocupacao_horaria (praia_id, dia_semana, hora, nivel_ocupacao, fonte, updated_at)\nVALUES ${values}\nON CONFLICT (praia_id, dia_semana, hora)\nDO UPDATE SET nivel_ocupacao = EXCLUDED.nivel_ocupacao, fonte = EXCLUDED.fonte, updated_at = EXCLUDED.updated_at`
  );
}

console.log(`${sqls.length} SQL batch(es) ready`);
return sqls.map(sql => ({ json: { sql } }));
